module.exports = function(RED) {

    function createAgentNode(name, defaultPrompt) {
        return function(config) {
            RED.nodes.createNode(this, config);
            const node = this;
            node.name = config.name;
            node.seedingPrompt = config.seedingPrompt || defaultPrompt;
            node.model = config.model;

            node.on("input", function(msg) {
                // shared logic for all agents
                msg.payload = {
                    model: node.model,
                    prompt: node.seedingPrompt,
                    input: msg.payload
                };
                node.send(msg);
            });
        }
    }
    RED.nodes.registerType(
        "Custom Output",
        createAgentNode("Custom Output", "Create me an awesome output!")
    );

    RED.nodes.registerType(
        "Requirements",
        createAgentNode("Requirements", "Produce Software Requirements from the input.")
    );

    RED.nodes.registerType(
        "User Story",
        createAgentNode("User Story", "Produce Software User Stories from the input.")
    );

    RED.nodes.registerType(
        "UML Class Diagram",
        createAgentNode("UML Class Diagram", "Produce a UML Class Diagram from the input.")
    );

}